final:
module two_bit_counter(  
    input clk,  
    input rst,  
    output reg [1:0] count  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin  
        if (rst)  
            count <= 2'b00;  
        else  
            count <= count + 1;  
    end  
endmodule
